INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (40011, "リリ", 24001, 125801, 1, 321, 2, 1, 1, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 0);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (40011, "クリア", 24001, 126001, 2, 322, 2, 1, 1, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 0);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (40011, "プレシア", 24001, 126101, 3, 323, 2, 1, 1, "んーと。\nこれ、あげる。\nはい", 0);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (40011, "リリ", 24001, 125801, 4, 324, 2, 2, 1, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 0);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (40011, "クリア", 24001, 126001, 5, 325, 2, 2, 1, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 0);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (40011, "プレシア", 24001, 126101, 6, 326, 2, 2, 1, "お兄。\nきてくれて、うれしい", 0);
